import functions_framework
from flask import jsonify, request


def set_cors_headers(response):
    """Set CORS headers on the response to allow requests from any origin."""
    response.headers["Access-Control-Allow-Origin"] = "*"
    response.headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, PATCH, OPTIONS"
    response.headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-Requested-With, Accept, Origin"
    response.headers["Access-Control-Max-Age"] = "3600"
    return response


@functions_framework.http
def main(request):
    """
    HTTP Cloud Function API entry point.
    Handles CORS preflight requests and routes to appropriate handlers.
    
    Args:
        request (flask.Request): The request object.
    
    Returns:
        flask.Response: The response object with CORS headers.
    """
    # Handle CORS preflight OPTIONS request
    if request.method == "OPTIONS":
        response = jsonify({"status": "ok"})
        response.status_code = 204
        return set_cors_headers(response)

    # Route requests based on method and path
    path = request.path.strip("/")
    method = request.method

    try:
        if path == "" or path == "health":
            response = handle_health(request)
        elif path == "api/data":
            response = handle_data(request, method)
        elif path == "api/users":
            response = handle_users(request, method)
        elif path.startswith("api/users/"):
            user_id = path.split("/")[-1]
            response = handle_user_by_id(request, method, user_id)
        elif path == "api/items":
            response = handle_items(request, method)
        elif path.startswith("api/items/"):
            item_id = path.split("/")[-1]
            response = handle_item_by_id(request, method, item_id)
        else:
            response = jsonify({
                "error": "Not Found",
                "message": f"The requested endpoint '/{path}' does not exist.",
                "available_endpoints": [
                    "/health",
                    "/api/data",
                    "/api/users",
                    "/api/users/<user_id>",
                    "/api/items",
                    "/api/items/<item_id>",
                ]
            })
            response.status_code = 404

    except Exception as e:
        response = jsonify({
            "error": "Internal Server Error",
            "message": str(e)
        })
        response.status_code = 500

    return set_cors_headers(response)


